INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible) - Cuarto Año', 'Productividad en la Laboriosidad', '1. Contrasta la información mediante la investigación para la realización de proyectos en el ámbito familiar y comunitario.', ARRAY['1.1. Recopila la información necesaria mediante técnicas pertinentes.', '1.2. Clasifica la información obtenida en función del proceso a ejecutar.', '1.3. Valora la información obtenida para la oportuna toma de decisiones.']),
('Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible) - Cuarto Año', 'Productividad en la Laboriosidad', '2. Plantea proyectos con control de calidad en su trabajo profesional.', ARRAY['2.1. Conoce las oportunidades y amenazas para la realización del proyecto.', '2.2. Verifica los procesos de control de calidad.', '2.3. Aplica métodos y normas en el manejo de los bienes y servicios.']),
('Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible) - Cuarto Año', 'Productividad en la Laboriosidad', '3. Promueve procesos en gestión de proyectos en instituciones que faciliten el desarrollo económico personal, familiar y comunitario.', ARRAY['3.1. Determina acciones que propician la gestión para la implementación del proyecto.', '3.2. Evalúa la pertinencia y conveniencia de las posibles alianzas.', '3.3. Ejecuta acciones que propician la realización ordenada y sistemática del proyecto.']);
